#include <bits/stdc++.h>
using namespace std;
int main()
{
    int m,sum,a[105];
    cin>>m;
    for(int i=0;i<=m-1;i++)
    {
        cin>>a[i];
    }
    for (int i = 0;i<= m-1;i++) {
        sum = 0;
        int temp=a[i];
        int count = to_string(temp).size();
        while(temp>0)
        {
            int t =temp%10;
            temp/=10;

            int ji = 1;
            for (int j = 0; j <= count-1; j++) {
                ji *= t;
            }
            sum += ji;
            //cout << t << " " << ji << endl;
        }
        if (sum == a[i]) {
            cout << "T"<< endl;
        } else {
            cout << "F"<< endl;
        }
    }
    return 0;
}
